import React, { useEffect, useState } from 'react'
import { Img_URL,fetchMovieList } from '../../utils/fetchApi';
import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';

const TopRated = () => {
  const [page,setPage]=useState(1);
  const [TopRatedMovieList,setTopRatedMovieList]=useState([])

  const loadMoreHandle=()=>{
   setPage((prev)=> prev + 1);
   refetch();
   setTopRatedMovieList((prev)=> [...prev,...TopratedList]);
 }

  const { isLoading,isError,error ,data: TopratedList,refetch} = useQuery({
      queryKey: ["TopratedList"],
      queryFn: () =>
        fetchMovieList("top_rated",`${page}`).then((res) => {
            if(page===1){
                setTopRatedMovieList(res.results);
                setPage(2);
            }
            return  res.results;
        }),
    });



    useEffect(()=>{
      refetch();
    },[refetch,page]);

    if (isLoading) {
      return (
        <div className="loading">
          <h1>Loading...</h1>
        </div>
      );
    } else if (isError) {
      return (
        <div className="error">
          <p>{error.message}</p>
        </div>
      );
    } else
return (
  <div className="Popular">
        <h1>Top-Rated Movies</h1>
        <div>
        {TopRatedMovieList?.map((item,index) => (
              item.poster_path!==null &&
            <Link to={`/movie/${item.id}`} className="card" key={index}>
              <img src={ item.poster_path!==null ?`${Img_URL}${ item.poster_path }`:""} alt="" />
            </Link>

        ))}
        </div>
        {<button onClick={loadMoreHandle}>More</button>}
      </div>
)
}

export default TopRated
